connectors.request_body:
{% set body = body_text | from_json %}
{
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v58.0/query?q=SELECT Id FROM Contact WHERE Email = '{{ user.email }}'",
      "referenceId": "foundContact"
    },
    {
      "method": "POST",
      "url": "/services/data/v58.0/sobjects/Case",
      "referenceId": "newCase",
      "body": {
        "Subject": "{{ body.subject }}",
        "Description": "{{ body.description }}",
        "SuppliedPhone": "{{ body.phone }}",
        "ContactId": "@{foundContact.records[0].Id}"
      }
    }
  ]
}

